  if (drag.kind === 'slide') {
    const card = e.target.closest('.card');
    if (!card || +card.dataset.idx === drag.from) return;
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
    clearDropMarkers();
    card.classList.add('drop-target');
  } else if (drag.kind === 'pane') {
    const pane = e.target.closest('.pane-group[data-pane-idx]');
    if (!pane) return;
    const card = pane.closest('.card');
    if (!card || +card.dataset.idx !== drag.slideIdx) return;
    if (+pane.dataset.paneIdx === drag.paneIdx) return;
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
    clearDropMarkers();
    pane.classList.add('drop-target');
  }
